            key={star}
            type="button"
            onClick={() => setFormData(prev => ({ ...prev, [field]: star }))}
            className={`p-1 transition-colors ${value >= star ? 'text-yellow-400' : 'text-slate-200'}`}
          >
            <Star className="w-5 h-5 fill-current" />
          </button>
        ))}
      </div>
    </div>
  );

